// frontend/src/pages/GamePlay.js
import React from 'react';
import { useNavigate } from 'react-router-dom';
import Questions from '../components/Questions';
import Lives from '../components/Lives';

export default function GamePlay() {
  const navigate = useNavigate();

  return (
    <div className="p-6 bg-yellow-50 min-h-screen max-w-2xl mx-auto border-x border-yellow-200">
      <div className="flex justify-between items-center mb-8">
        <button onClick={() => navigate('/timeline')} className="text-yellow-800 font-bold">⬅ Quay lại</button>
        <div className="w-1/2 bg-gray-300 h-4 rounded-full mx-4">
          <div className="bg-green-500 h-4 rounded-full w-1/3 transition-all duration-500"></div>
        </div>
        <Lives />
      </div>

      <div className="bg-white p-6 rounded-xl shadow-lg border border-yellow-200">
        <h2 className="text-2xl font-bold text-red-900 mb-6 text-center leading-relaxed">
          Ai là người lãnh đạo nhân dân ta đánh thắng quân Nam Hán trên sông Bạch Đằng năm 938?
        </h2>
        <Questions />
      </div>
    </div>
  );
}
